  mem_fill_both: { bg:'Попълни и двете полета.', ru:'Заполни оба поля.', uk:'Заповни обидва поля.', en:'Fill in both fields.', de:'Fülle beide Felder aus.', fr:'Remplis les deux champs.', es:'Completa ambos campos.', 'es-MX':'Completa ambos campos.', it:'Compila entrambi i campi.', pt:'Preencha os dois campos.', ar:'املأ الحقلين.', hi:'दोनों फ़ील्ड भरो।', ja:'両方の欄を入力してください。', ky:'Эки талааны тең толтур.', 'zh-Hant':'請填寫兩個欄位。' },
  mem_added: { bg:'Добавено в паметта.', ru:'Добавлено в память.', uk:'Додано в пам’ять.', en:'Added to memory.', de:'Zum Gedächtnis hinzugefügt.', fr:'Ajouté à la mémoire.', es:'Añadido a la memoria.', 'es-MX':'Añadido a la memoria.', it:'Aggiunto alla memoria.', pt:'Adicionado à memória.', ar:'أُضيف إلى الذاكرة.', hi:'स्मृति में जोड़ा गया।', ja:'記憶に追加しました。', ky:'Эске кошулду.', 'zh-Hant':'已加入記憶。' },
