  mem_key_label: { bg:'Ключ / тригер', ru:'Ключ / триггер', uk:'Ключ / тригер', en:'Key / trigger', de:'Schlüssel / Auslöser', fr:'Clé / déclencheur', es:'Clave / disparador', 'es-MX':'Clave / disparador', it:'Chiave / trigger', pt:'Chave / gatilho', ar:'مفتاح / مُحفّز', hi:'कुंजी / ट्रिगर', ja:'キー / トリガー', ky:'Ачкыч / триггер', 'zh-Hant':'鍵 / 觸發' },
