  mem_add_btn: { bg:'+ Добави спомен', ru:'+ Добавить воспоминание', uk:'+ Додати спогад', en:'+ Add memory', de:'+ Erinnerung hinzufügen', fr:'+ Ajouter un souvenir', es:'+ Añadir recuerdo', 'es-MX':'+ Añadir recuerdo', it:'+ Aggiungi ricordo', pt:'+ Adicionar memória', ar:'+ أضف ذكرى', hi:'+ स्मृति जोड़ें', ja:'+ 記憶を追加', ky:'+ Эстелик кош', 'zh-Hant':'+ 新增記憶' },
  mem_count: { bg:'Запомнени неща ({0})', ru:'Запомнено ({0})', uk:'Запам’ятано ({0})', en:'Remembered items ({0})', de:'Gemerkte Einträge ({0})', fr:'Éléments mémorisés ({0})', es:'Elementos recordados ({0})', 'es-MX':'Elementos recordados ({0})', it:'Elementi memorizzati ({0})', pt:'Itens lembrados ({0})', ar:'العناصر المحفوظة ({0})', hi:'याद रखी चीज़ें ({0})', ja:'記憶した項目 ({0})', ky:'Эстелген нерселер ({0})', 'zh-Hant':'已記住的項目（{0}）' },
  mem_empty: { bg:'Още нищо. Иди в чата и ме научи на нещо 🙂', ru:'Пока ничего. Зайди в чат и научи меня чему-нибудь 🙂', uk:'Поки нічого. Зайди в чат і навчи мене чомусь 🙂', en:'Nothing yet. Go to chat and teach me something 🙂', de:'Noch nichts. Geh zum Chat und bring mir etwas bei 🙂', fr:'Rien encore. Va au chat et apprends-moi quelque chose 🙂', es:'Nada todavía. Ve al chat y enséñame algo 🙂', 'es-MX':'Nada todavía. Ve al chat y enséñame algo 🙂', it:'Ancora niente. Vai alla chat e insegnami qualcosa 🙂', pt:'Ainda nada. Vá ao chat e me ensine algo 🙂', ar:'لا شيء بعد. اذهب إلى الدردشة وعلّمني شيئًا 🙂', hi:'अभी कुछ नहीं। चैट में जाओ और मुझे कुछ सिखाओ 🙂', ja:'まだ何もありません。チャットで何か教えてください 🙂', ky:'Азырынча эч нерсе жок. Маекке кирип, мени бир нерсеге үйрөт 🙂', 'zh-Hant':'目前還沒有。去聊天教我點什麼吧 🙂' },
